package ru.memearena.analytics.application;
import org.springframework.http.HttpStatus; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import ru.memearena.analytics.api.*; import ru.memearena.analytics.domain.*; import ru.memearena.analytics.infrastructure.ProductEventRepository; import ru.memearena.error.*; import ru.memearena.meme.domain.ModerationStatus; import ru.memearena.ratelimit.RateLimiterService; import ru.memearena.scout.infrastructure.MemePredictionRepository; import ru.memearena.session.infrastructure.UserSessionRepository; import ru.memearena.tournament.infrastructure.TournamentVoteRepository; import ru.memearena.user.infrastructure.UserProfileRepository; import ru.memearena.vote.infrastructure.VoteRepository; import jakarta.persistence.EntityManager; import java.time.*; import java.util.UUID;
@Service public class ProductAnalyticsService { private final ProductEventRepository events; private final UserSessionRepository sessions; private final RateLimiterService rate; private final Clock clock; private final UserProfileRepository users; private final VoteRepository votes; private final MemePredictionRepository predictions; private final TournamentVoteRepository tournamentVotes; private final EntityManager em; public ProductAnalyticsService(ProductEventRepository events,UserSessionRepository sessions,RateLimiterService rate,Clock clock,UserProfileRepository users,VoteRepository votes,MemePredictionRepository predictions,TournamentVoteRepository tournamentVotes,EntityManager em){this.events=events;this.sessions=sessions;this.rate=rate;this.clock=clock;this.users=users;this.votes=votes;this.predictions=predictions;this.tournamentVotes=tournamentVotes;this.em=em;} @Transactional public void ingest(UUID userId,UUID sessionId,ProductEventRequest req){rate.check("product-events",userId.toString(),120,60); ProductEventType type; try{type=ProductEventType.valueOf(req.eventType());}catch(Exception e){throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.VALIDATION_ERROR,"Unsupported product event type");} Instant now=Instant.now(clock); if(req.occurredAt().isAfter(now.plus(Duration.ofMinutes(5)))||req.occurredAt().isBefore(now.minus(Duration.ofDays(30)))) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.VALIDATION_ERROR,"Product event timestamp is outside accepted range"); String installation=sessions.findById(sessionId).map(s->s.getInstallationId()).orElse(null); events.save(new ProductEvent(UUID.randomUUID(),userId,installation,type,"ANDROID",req.occurredAt(),now,trim(req.appVersion(),30),trim(req.platform(),20))); } @Transactional(readOnly=true) public AnalyticsSummaryResponse summary(Instant from,Instant to){ if(to.isBefore(from)) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.VALIDATION_ERROR,"Invalid analytics range"); long newUsers=users.count((root,q,cb)->cb.between(root.get("createdAt"),from,to)); long active=events.activeUsers(from,to); long appOpens=events.appOpens(from,to); long completed=votes.count((root,q,cb)->cb.between(root.get("createdAt"),from,to)); long uploaded=(Long)em.createQuery("select count(m) from Meme m where m.createdAt between :from and :to").setParameter("from",from).setParameter("to",to).getSingleResult(); long createdPredictions=predictions.count((root,q,cb)->cb.between(root.get("predictedAt"),from,to)); long tour=tournamentVotes.count((root,q,cb)->cb.between(root.get("createdAt"),from,to)); long opened=events.usersWhoOpenedBattle(from,to); long voted=events.usersWhoCompletedVote(from,to); double conv=opened==0?0.0:((double)voted)/opened; return new AnalyticsSummaryResponse(newUsers,active,appOpens,completed,uploaded,createdPredictions,tour,opened,voted,conv);} private static String trim(String v,int max){return v==null?null:v.length()<=max?v:v.substring(0,max);} }
